import tensorflow as tf
import pandas as pd
import numpy as np
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import os
from PIL import Image
import io
from sklearn.model_selection import train_test_split
from sklearn.preprocessing import LabelEncoder
import uuid

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = 'uploads'
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024

# Create upload directory
os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)

# Global model and preprocessing objects
model = None
label_encoder = LabelEncoder()
class_names = []

def create_model(num_classes):
    model = tf.keras.Sequential([
        tf.keras.layers.Conv2D(32, (3, 3), activation='relu', input_shape=(224, 224, 3)),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(128, (3, 3), activation='relu'),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Flatten(),
        tf.keras.layers.Dense(512, activation='relu'),
        tf.keras.layers.Dropout(0.5),
        tf.keras.layers.Dense(num_classes, activation='softmax')
    ])
    
    model.compile(optimizer='adam',
                  loss='categorical_crossentropy',
                  metrics=['accuracy'])
    return model

def load_and_preprocess_data(csv_path, image_folder):
    df = pd.read_csv(csv_path)
    images = []
    labels = []
    
    for _, row in df.iterrows():
        try:
            img_path = os.path.join(image_folder, row['image_name'])
            img = Image.open(img_path).convert('RGB')
            img = img.resize((224, 224))
            img_array = np.array(img)
            images.append(img_array)
            labels.append(row['label'])
        except Exception as e:
            print(f"Error loading image {row['image_name']}: {e}")
            continue
    
    return np.array(images), np.array(labels)

def train_model(csv_path, image_folder):
    global model, label_encoder, class_names
    
    images, labels = load_and_preprocess_data(csv_path, image_folder)
    
    # Encode labels
    encoded_labels = label_encoder.fit_transform(labels)
    class_names = label_encoder.classes_
    
    # Convert to categorical
    num_classes = len(np.unique(encoded_labels))
    y = tf.keras.utils.to_categorical(encoded_labels, num_classes)
    
    # Split data
    X_train, X_test, y_train, y_test = train_test_split(
        images, y, test_size=0.2, random_state=42
    )
    
    # Normalize images
    X_train = X_train.astype('float32') / 255.0
    X_test = X_test.astype('float32') / 255.0
    
    # Create and train model
    model = create_model(num_classes)
    
    history = model.fit(
        X_train, y_train,
        epochs=10,
        batch_size=32,
        validation_data=(X_test, y_test),
        verbose=1
    )
    
    return model, history

def add_training_example(image_data, label):
    global model, label_encoder, class_names
    
    # Save image
    img = Image.open(io.BytesIO(image_data)).convert('RGB')
    img = img.resize((224, 224))
    img_array = np.array(img)
    
    # Encode label
    try:
        encoded_label = label_encoder.transform([label])[0]
    except ValueError:
        # New label, add to encoder
        new_classes = list(label_encoder.classes_) + [label]
        label_encoder.fit(new_classes)
        encoded_label = len(label_encoder.classes_) - 1
    
    # Retrain model with new example
    # This is a simplified version - in practice, you'd want to use a more sophisticated approach
    # like incremental learning or maintaining a larger dataset
    
    return True

@app.route('/train', methods=['POST'])
def train():
    try:
        if 'csv_file' not in request.files or 'image_folder' not in request.form:
            return jsonify({'error': 'Missing files or parameters'}), 400
        
        csv_file = request.files['csv_file']
        image_folder = request.form['image_folder']
        
        if csv_file.filename == '':
            return jsonify({'error': 'No selected CSV file'}), 400
        
        # Save CSV file
        csv_filename = secure_filename(csv_file.filename)
        csv_path = os.path.join(app.config['UPLOAD_FOLDER'], csv_filename)
        csv_file.save(csv_path)
        
        # Train model
        model, history = train_model(csv_path, image_folder)
        
        return jsonify({
            'message': 'Training completed successfully',
            'accuracy': float(history.history['accuracy'][-1]),
            'val_accuracy': float(history.history['val_accuracy'][-1])
        })
    
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/contribute', methods=['POST'])
def contribute():
    try:
        if 'image' not in request.files or 'label' not in request.form:
            return jsonify({'error': 'Missing image or label'}), 400
        
        image_file = request.files['image']
        label = request.form['label']
        
        if image_file.filename == '':
            return jsonify({'error': 'No selected image'}), 400
        
        # Add training example
        image_data = image_file.read()
        success = add_training_example(image_data, label)
        
        if success:
            return jsonify({'message': 'Training example added successfully'})
        else:
            return jsonify({'error': 'Failed to add training example'}), 500
    
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/predict', methods=['POST'])
def predict():
    try:
        if 'image' not in request.files:
            return jsonify({'error': 'Missing image'}), 400
        
        image_file = request.files['image']
        image_data = image_file.read()
        
        # Load and preprocess image
        img = Image.open(io.BytesIO(image_data)).convert('RGB')
        img = img.resize((224, 224))
        img_array = np.array(img)
        img_array = img_array.astype('float32') / 255.0
        img_array = np.expand_dims(img_array, axis=0)
        
        # Make prediction
        predictions = model.predict(img_array)
        predicted_class = np.argmax(predictions[0])
        confidence = predictions[0][predicted_class]
        
        return jsonify({
            'predicted_class': class_names[predicted_class],
            'confidence': float(confidence),
            'all_predictions': dict(zip(class_names, predictions[0].tolist()))
        })
    
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)